+   * Used by SelfLearningRvfBackend to prevent catastrophic forgetting.
+   */
+  ewcPenalty(params: Float32Array): number {
+    if (this._ewcManager) {
+      try { return this._ewcManager.computePenalty(Array.from(params)); } catch { /* fallback */ }
